import React from "react";
import {getPrimeDataType, matchModesOptions, showFilterMenu,} from "./Constants";
import {PickFilterElement} from "./Filter";
import {Column as PrimeColumn, type ColumnProps} from "primereact/column";
import {fontSizeMapping, sizeMapping,} from "../constants";
import {FilterMatchMode} from "primereact/api";
import {type DataTableFilterMeta, type DataTableFilterMetaData,} from "primereact/datatable";
import {matchModeDefaultValues} from "./assets";
import moment from "moment/moment";
import BodyTemplate from "./BodyTemplate";
import {Flex} from "../../../_compat";
import {type IColumn, type IPaginationRequest} from "@lmb-it/kitsconcerto-types";
import {PickEditorElement} from "./Editor";

interface IColumnProps {
    field: IColumn<any>;
    index: number;
    serverSideRequest: IPaginationRequest;
    tableSize: "small" | "normal" | "large";
    keyColumn: string;
    isLoading: boolean;
    debounceFilterWaitTime: number;
    filterMode: 'enter' | 'debounce';
    t: (key: string) => string;
    themeHeaderCellStyle?: React.CSSProperties;
    themeBodyCellStyle?: React.CSSProperties;
}

const columnFunction: (props: IColumnProps) => React.JSX.Element = ({
                                                                        field,
                                                                        index,
                                                                        serverSideRequest,
                                                                        keyColumn,
                                                                        tableSize,
                                                                        isLoading,
                                                                        debounceFilterWaitTime,
                                                                        filterMode,
                                                                        t,
                                                                        themeHeaderCellStyle,
                                                                        themeBodyCellStyle,
                                                                    }) => {
    const {
        label,
        labelTooltip,
        name,
        body,
        bodyTemplate,
        filter,
        editor,
        globalStyle,
        headerStyle,
        filterStyle,
        bodyStyle,
        isSortable,
        selectionMode,
        ...localProps
    } = field;
    let matchMode: FilterMatchMode | undefined = undefined;

    if (name && name in serverSideRequest.filters && !!filter) {
        const a = (serverSideRequest.filters as DataTableFilterMeta)[
            name
            ] as DataTableFilterMetaData;

        if ("matchMode" in a) {
            matchMode = a.matchMode as FilterMatchMode;
        } else {
            if ("isMultiple" in filter && filter.isMultiple) {
                matchMode = matchModeDefaultValues["multiSelect"];
            } else {
                matchMode = matchModeDefaultValues[filter.type];
            }
        }
    }

    const bodyBuilder = (field: IColumn<any>): ColumnProps["body"] =>
        (data, options) => {
            if (!field.name) {
                return null;
            }
            const value = data[field.name];
            let toReturn: any = value;

            if (body) {
                // options cast bridges native/web ColumnBodyOptions (moduleSuffixes conflict)
                toReturn = body(value, data, options as any);
            } else if (value instanceof Date) {
                const m = moment(value, "YYYY-MM-DDTHH:mm:ss.SSSSSSZ");

                toReturn = m.format("YYYY-MMM-DD");
            }

            if (bodyTemplate) {
                return (
                    <Flex alignItems={"center"} justifyContent={"center"}>
                        <BodyTemplate
                            value={value}
                            body={toReturn}
                            bodyTemplate={bodyTemplate}
                        />
                    </Flex>
                );
            }

            return toReturn;
        }

    return (
        <PrimeColumn
            key={index}
            field={name}
            header={label}
            selectionMode={selectionMode}
            headerTooltip={labelTooltip}
            headerTooltipOptions={{
                position: "top",
            }}
            sortable={isSortable}
            filter={!!filter}
            bodyStyle={{
                //Style of columns in the results
                padding: sizeMapping[tableSize],
                fontSize: "small",
                ...themeBodyCellStyle,
                ...bodyStyle,
                ...globalStyle,
            }}
            headerStyle={{
                //Style of columns in the headers row
                fontSize: fontSizeMapping[tableSize],
                ...themeHeaderCellStyle,
                ...headerStyle,
                ...globalStyle,
            }}
            filterHeaderStyle={{
                ...filterStyle,
                ...globalStyle,
            }}
            //@ts-ignore
            style={{
                //Style of columns in the filters row
                // ...filterStyle,
                ...(globalStyle ?? {}),
            }}
            filterField={name}
            columnKey={keyColumn}
            // rowReorder
            filterType={filter?.type}
            dataType={getPrimeDataType(filter)}
            showClearButton={
                !["tristate", "buttons"].includes(filter?.type ?? " ")
            }
            filterMatchModeOptions={matchModesOptions(filter, t)}
            showFilterMenu={showFilterMenu(filter)}
            body={!isLoading ? bodyBuilder(field) : undefined}
            editor={editor?(e) => {
                return <PickEditorElement Editor={editor} options={e} isLoading={isLoading}/>
            }:undefined}
            filterMatchMode={matchMode}
            filterElement={(options) => (
                <PickFilterElement
                    isLoading={isLoading}
                    filter={filter}
                    options={options}
                    debounceFilterWaitTime={debounceFilterWaitTime}
                    filterMode={filterMode}
                />
            )}
            {...localProps}
        />
    );
};

export default columnFunction;
